// ── Cache check (Supabase) ──
// TODO: Before calling expensive APIs, check:
// SELECT * FROM agent_cache WHERE cache_key = MD5(city+area+business_type+agent_id)
//   AND updated_at > NOW() - INTERVAL '7 days'
// If cache hit → return cached data immediately
// Implementation: add a Supabase HTTP call before API calls with cache_key lookup

const all = $input.all();
const inputs = $('Parse & Validate Inputs').item.json;

let overpassData = null;
let absLpiCsv    = null;
let absCpiCsv    = null;
let rbaRawCsv    = null;
let dataGovData  = null;

// ── SEPARATE RESULTS BY STRUCTURE ──
// Order in merge: [0]=Overpass, [1]=LPI, [2]=CPI, [3]=RBA, [4]=dataGov
for (let i = 0; i < all.length; i++) {
  const j = all[i].json;
  const bodyStr = j?.body ?? (typeof j === 'string' ? j : null);

  // Overpass: has elements array
  if (j?.elements !== undefined) { overpassData = j; continue; }

  // data.gov.au: has result.results
  if (j?.result?.results) { dataGovData = j; continue; }

  // CSV responses — n8n text mode returns { body: '...' } or just the string
  if (bodyStr && typeof bodyStr === 'string') {
    const upper = bodyStr.toUpperCase();
    if (upper.includes('LPI') || upper.includes('LABOUR_PRICE') || upper.includes('HOURLY')) {
      absLpiCsv = bodyStr; continue;
    }
    if (upper.includes('CPI') || upper.includes('FOOD') || upper.includes('NON-ALCOHOLIC')) {
      absCpiCsv = bodyStr; continue;
    }
    // RBA CSV has Westpac or Index or G17 patterns
    if (upper.includes('WESTPAC') || upper.includes('CONSUMER') || i === 3) {
      rbaRawCsv = bodyStr; continue;
    }
    // Fallback assignment by position
    if (!absLpiCsv) { absLpiCsv = bodyStr; continue; }
    if (!absCpiCsv) { absCpiCsv = bodyStr; continue; }
    if (!rbaRawCsv) { rbaRawCsv = bodyStr; continue; }
  }
}

// ── HELPER: PARSE ABS SDMX-CSV ──
// ABS CSV format: DATAFLOW,DIM1,DIM2,...,TIME_PERIOD,OBS_VALUE,...
function parseAbsCsv(csv) {
  if (!csv || typeof csv !== 'string') return null;
  try {
    const lines = csv.split('\n').map(l => l.trim()).filter(l => l);
    if (lines.length < 2) return null;
    const headers = lines[0].split(',').map(h => h.trim().replace(/"/g, ''));
    const timePeriodIdx = headers.findIndex(h => h === 'TIME_PERIOD');
    const obsValueIdx   = headers.findIndex(h => h === 'OBS_VALUE');
    if (timePeriodIdx === -1 || obsValueIdx === -1) return null;

    const dataLines = lines.slice(1).filter(l => !/^[A-Z]/.test(l.trim()) || l.includes('-Q') || l.includes('-'));
    const observations = [];
    for (const line of dataLines) {
      const parts = line.split(',');
      if (parts.length <= Math.max(timePeriodIdx, obsValueIdx)) continue;
      const period = parts[timePeriodIdx]?.trim().replace(/"/g, '');
      const value  = parseFloat(parts[obsValueIdx]?.trim().replace(/"/g, ''));
      if (period && !isNaN(value)) observations.push({ period, value });
    }
    return observations.length > 0 ? observations : null;
  } catch(e) {
    return null;
  }
}

// ── ABS LABOUR PRICE INDEX ──
let lpiYoyChange = null;
let lpiLabel = 'ABS Labour Price Index unavailable';
let lpiObs = parseAbsCsv(absLpiCsv);

if (lpiObs && lpiObs.length >= 5) {
  const latest  = lpiObs[lpiObs.length - 1].value;
  const yoyBase = lpiObs[lpiObs.length - 5]?.value;
  if (latest && yoyBase) {
    lpiYoyChange = parseFloat(((latest - yoyBase) / yoyBase * 100).toFixed(1));
    lpiLabel = `ABS Labour Price Index (live): +${lpiYoyChange}% annual wage growth — ${lpiYoyChange > 4 ? 'High' : lpiYoyChange > 3 ? 'Moderate' : 'Low'} labour cost pressure`;
  }
} else if (absLpiCsv) {
  lpiLabel = 'ABS LPI: data fetched but series key not matched — check dataflow key 1.1.1.10.Q';
}

// ── ABS CPI FOOD ──
let cpiYoyChange = null;
let cpiLabel = 'ABS Food CPI unavailable';
let cpiObs = parseAbsCsv(absCpiCsv);

if (cpiObs && cpiObs.length >= 5) {
  const latest  = cpiObs[cpiObs.length - 1].value;
  const yoyBase = cpiObs[cpiObs.length - 5]?.value;
  if (latest && yoyBase) {
    cpiYoyChange = parseFloat(((latest - yoyBase) / yoyBase * 100).toFixed(1));
    const pressure = cpiYoyChange > 5 ? 'High' : cpiYoyChange > 2 ? 'Moderate' : 'Low';
    cpiLabel = `ABS Food & Non-Alcoholic CPI (live): +${cpiYoyChange}% YoY — ${pressure} food cost pressure on COGS`;
  }
} else if (absCpiCsv) {
  cpiLabel = 'ABS CPI: data fetched but series key not matched — check dataflow key 1.50.10.Q';
}

// ── RBA CONSUMER SENTIMENT ──
let rbaConsumerSentiment = null;
let rbaLabel = 'RBA Consumer Sentiment unavailable';

if (rbaRawCsv && typeof rbaRawCsv === 'string') {
  try {
    const lines = rbaRawCsv.split('\n').map(l => l.trim()).filter(l => l);
    // G17: rows start with a date like Jan-2024 or 2024-01 or 2024Jan
    const dataLines = lines.filter(l =>
      /^[A-Za-z]{3}[-\s]\d{4}/.test(l) || // Jan 2024 or Jan-2024
      /^\d{4}[-\s][A-Za-z]{3}/.test(l) || // 2024-Jan
      /^\d{4}-\d{2}/.test(l)              // 2024-01
    );
    if (dataLines.length > 0) {
      const lastLine = dataLines[dataLines.length - 1];
      const parts = lastLine.split(',').map(p => p.trim().replace(/"/g, ''));
      const date   = parts[0];
      // Find the first numeric value after the date
      const index  = parseFloat(parts.slice(1).find(p => !isNaN(parseFloat(p))));
      if (!isNaN(index) && index > 0) {
        const label = index > 100 ? 'Optimistic' : index > 90 ? 'Neutral' : 'Pessimistic';
        rbaConsumerSentiment = { date, index, label };
        rbaLabel = `RBA/Westpac Consumer Sentiment (${date}): ${index} — ${label}`;
      }
    }
    if (!rbaConsumerSentiment) {
      rbaLabel = `RBA CSV fetched (${rbaRawCsv.length} chars) but date pattern not matched — check g17hist.csv format`;
    }
  } catch(e) {
    rbaLabel = 'RBA CSV parse error: ' + e.message;
  }
}

// ── OVERPASS: ANCHOR STORES ──
const anchorElements = overpassData?.elements || [];
const anchorChains = [
  { key: 'woolworths', label: 'Woolworths', tier: 'Supermarket', footfall_boost: 'High' },
  { key: 'coles',      label: 'Coles',      tier: 'Supermarket', footfall_boost: 'High' },
  { key: 'aldi',       label: 'Aldi',       tier: 'Supermarket', footfall_boost: 'Medium' },
  { key: 'iga',        label: 'IGA',        tier: 'Supermarket', footfall_boost: 'Medium' },
  { key: 'kmart',      label: 'Kmart',      tier: 'Discount',    footfall_boost: 'High' },
  { key: 'big w',      label: 'Big W',      tier: 'Discount',    footfall_boost: 'High' },
  { key: 'target',     label: 'Target',     tier: 'Discount',    footfall_boost: 'Medium' },
  { key: 'myer',       label: 'Myer',       tier: 'Department',  footfall_boost: 'Medium' },
  { key: 'david jones',label: 'David Jones',tier: 'Department',  footfall_boost: 'Medium' },
  { key: 'bunnings',   label: 'Bunnings',   tier: 'Hardware',    footfall_boost: 'High' },
  { key: 'chemist warehouse', label: 'Chemist Warehouse', tier: 'Pharmacy', footfall_boost: 'Medium' },
  { key: 'mcdonald',  label: "McDonald's",  tier: 'QSR',         footfall_boost: 'Medium' },
  { key: 'subway',     label: 'Subway',     tier: 'QSR',         footfall_boost: 'Low' },
  { key: 'starbucks',  label: 'Starbucks',  tier: 'Coffee',      footfall_boost: 'Medium' },
  { key: '7-eleven',   label: '7-Eleven',   tier: 'Convenience', footfall_boost: 'Low' }
];

const foundAnchors = [];
for (const el of anchorElements) {
  const name = (el.tags?.name || el.tags?.brand || '').toLowerCase();
  for (const chain of anchorChains) {
    if (name.includes(chain.key)) {
      foundAnchors.push({ name: el.tags?.name || chain.label, chain: chain.label, tier: chain.tier, footfall_boost: chain.footfall_boost });
      break;
    }
  }
}
const seenChains = new Set();
const uniqueAnchors = foundAnchors.filter(a => { if (seenChains.has(a.chain)) return false; seenChains.add(a.chain); return true; });
const anchorScore = Math.min(100, uniqueAnchors.reduce((s,a) => s + (a.footfall_boost==='High'?30:a.footfall_boost==='Medium'?20:10), 0));
const hasMajorSupermarket = uniqueAnchors.some(a => ['Woolworths','Coles','Aldi'].includes(a.chain));
const anchorSummary = uniqueAnchors.length > 0 ? uniqueAnchors.map(a => `${a.chain} (${a.tier})`).join(', ') : 'No major anchor stores within 300m';

// ── DATA.GOV.AU ──
let dataGovDatasets = [];
let dataGovLabel = 'No relevant datasets found on data.gov.au';
if (dataGovData?.result?.results?.length > 0) {
  dataGovDatasets = dataGovData.result.results.slice(0,3).map(d => ({ title: d.title || '', org: d.organization?.title || '' }));
  dataGovLabel = `data.gov.au: ${dataGovDatasets.map(d => d.title).join(', ')}`;
}

// ── STATE CONTEXT ──
const stateContext = {
  'VIC': { min_wage_casual: 25.41, food_reg: 'Food Act 1984 (Vic) — local council, $300-600/yr', liquor_reg: 'Liquor Control Reform Act 1998 — VCGLR, $800-3500/yr', payroll_tax_threshold: 700000 },
  'NSW': { min_wage_casual: 25.41, food_reg: 'Food Regulation 2015 (NSW) — local council, $200-500/yr', liquor_reg: 'Liquor Act 2007 — OLGR, $500-4000/yr', payroll_tax_threshold: 1200000 },
  'QLD': { min_wage_casual: 25.41, food_reg: 'Food Act 2006 (Qld) — local council, $200-500/yr', liquor_reg: 'Liquor Act 1992 (Qld) — OLGR, $600-3000/yr', payroll_tax_threshold: 1300000 },
  'WA':  { min_wage_casual: 25.41, food_reg: 'Food Act 2008 (WA) — local council, $200-500/yr', liquor_reg: 'Liquor Control Act 1988 (WA), $400-2000/yr', payroll_tax_threshold: 1000000 },
  'SA':  { min_wage_casual: 25.41, food_reg: 'Food Act 2001 (SA) — local council, $150-400/yr', liquor_reg: 'Liquor Licensing Act 1997 (SA) — LBSA, $400-2500/yr', payroll_tax_threshold: 1500000 },
  'ACT': { min_wage_casual: 25.41, food_reg: 'Food Act 2001 (ACT) — ACT Health, $200-500/yr', liquor_reg: 'Liquor Act 2010 (ACT), $500-3000/yr', payroll_tax_threshold: 2000000 },
  'TAS': { min_wage_casual: 25.41, food_reg: 'Food Act 2003 (Tas) — local council, $150-400/yr', liquor_reg: 'Liquor Licensing Act 1990 (Tas), $400-2000/yr', payroll_tax_threshold: 1250000 },
  'NT':  { min_wage_casual: 25.41, food_reg: 'Food Act 2004 (NT) — NT Health, $150-350/yr', liquor_reg: 'Liquor Act 2019 (NT), $500-3000/yr', payroll_tax_threshold: 1500000 }
};
const stateCode = inputs.state_code || 'VIC';
const stateRegs = stateContext[stateCode] || stateContext['VIC'];

// ── ECONOMIC HEALTH SCORE ──
const sentimentScore     = rbaConsumerSentiment ? (rbaConsumerSentiment.index > 105 ? 90 : rbaConsumerSentiment.index > 95 ? 70 : rbaConsumerSentiment.index > 85 ? 50 : 30) : 50;
const labourPressureScore= lpiYoyChange !== null ? (lpiYoyChange < 3 ? 80 : lpiYoyChange < 5 ? 60 : lpiYoyChange < 7 ? 40 : 20) : 50;
const cpiPressureScore   = cpiYoyChange !== null ? (cpiYoyChange < 2 ? 85 : cpiYoyChange < 4 ? 65 : cpiYoyChange < 7 ? 40 : 20) : 50;
const economicHealthScore = Math.round(anchorScore*0.35 + sentimentScore*0.25 + labourPressureScore*0.20 + cpiPressureScore*0.20);

return [{ json: {
  business_type: inputs.business_type, industry_category: inputs.industry_category,
  city: inputs.city, area: inputs.area, locality: inputs.locality,
  country: inputs.country, currency: inputs.currency,
  monthly_rent_budget_max: inputs.monthly_rent_budget_max, setup_budget: inputs.setup_budget,
  email: inputs.email, lat: inputs.lat, lng: inputs.lng, state_code: stateCode,
  anchor_stores: uniqueAnchors, anchor_count: uniqueAnchors.length, anchor_score: anchorScore,
  has_major_supermarket: hasMajorSupermarket, anchor_summary: anchorSummary,
  lpi_yoy_change: lpiYoyChange, lpi_label: lpiLabel,
  cpi_yoy_change: cpiYoyChange, cpi_label: cpiLabel,
  rba_sentiment: rbaConsumerSentiment, rba_label: rbaLabel,
  data_gov_datasets: dataGovDatasets, data_gov_label: dataGovLabel,
  state_regs: stateRegs,
  economic_health_score: economicHealthScore,
  debug: {
    abs_lpi_csv_received: absLpiCsv ? absLpiCsv.length + ' chars' : 'null',
    abs_cpi_csv_received: absCpiCsv ? absCpiCsv.length + ' chars' : 'null',
    rba_csv_received:     rbaRawCsv ? rbaRawCsv.length + ' chars' : 'null',
    lpi_obs_count:        lpiObs ? lpiObs.length : 0,
    cpi_obs_count:        cpiObs ? cpiObs.length : 0
  },
  data_sources: {
    overpass_anchors:  `${uniqueAnchors.length} major anchors found within 300m`,
    abs_labour_price:  lpiLabel,
    abs_food_cpi:      cpiLabel,
    rba_sentiment:     rbaLabel,
    data_gov_au:       dataGovLabel,
    state_regulations: `${stateCode} regulatory context (verified from legislation)`,
    geocoords_used:    inputs.lat && inputs.lng ? `${inputs.lat}, ${inputs.lng}` : 'Fallback coordinates'
  }
}}];

const inputJson = $input.first().json;
const rawText = inputJson.output || inputJson.text || JSON.stringify(inputJson);
let analysis;
try {
  let cleaned = rawText.trim()
    .replace(/^```json\s*/i,'').replace(/^```\s*/i,'').replace(/```\s*$/i,'').trim();
  const s = cleaned.indexOf('{'), e = cleaned.lastIndexOf('}');
  if (s !== -1 && e > s) cleaned = cleaned.slice(s, e+1);
  cleaned = cleaned.replace(/(:\s*)(\d{1,3}(?:,\d{3})+)([,\}\]\s\n])/g,(m,pre,num,post)=>pre+num.replace(/,/g,'')+post);
  analysis = JSON.parse(cleaned);
} catch(e) {
  analysis = { parse_error: true, raw_response: rawText.slice(0,800) };
}
const d = $('Compute Economic Context').first().json;
return [{ json: {
  agent_id:   'A8',
  agent_name: 'Economic Context (Overpass + ABS + RBA)',
  status:     analysis.parse_error ? 'error' : 'success',
  timestamp:  new Date().toISOString(),
  email:      d.email,
  inputs_used: { business_type: d.business_type, industry_category: d.industry_category, location: `${d.area}, ${d.city}`, state: d.state_code, coordinates: `${d.lat}, ${d.lng}` },
  data_sources: d.data_sources,
  debug: d.debug,
  computed: {
    anchor_score: d.anchor_score, anchor_count: d.anchor_count,
    has_major_supermarket: d.has_major_supermarket,
    economic_health_score: d.economic_health_score,
    lpi_yoy_change: d.lpi_yoy_change, cpi_yoy_change: d.cpi_yoy_change,
    rba_index: d.rba_sentiment?.index || null
  },
  outputs: {
    economic_health_score:    analysis.economic_health_score    ?? d.economic_health_score,
    economic_verdict:         analysis.economic_verdict          || null,
    anchor_store_analysis:    analysis.anchor_store_analysis     || { count_within_300m: d.anchor_count, anchor_score: d.anchor_score, major_supermarket_present: d.has_major_supermarket, anchors_found: d.anchor_stores.map(a=>a.chain) },
    labour_cost_analysis:     analysis.labour_cost_analysis      || { annual_wage_growth_pct: d.lpi_yoy_change, min_casual_wage_aud: 25.41 },
    cpi_impact:               analysis.cpi_impact                || { food_cpi_yoy_pct: d.cpi_yoy_change },
    consumer_sentiment:       analysis.consumer_sentiment         || { index_value: d.rba_sentiment?.index || null },
    state_regulatory_summary: analysis.state_regulatory_summary  || { state: d.state_code, food_registration: d.state_regs?.food_reg, liquor_licensing: d.state_regs?.liquor_reg },
    key_economic_risks:       analysis.key_economic_risks         || [],
    key_economic_tailwinds:   analysis.key_economic_tailwinds     || [],
    data_gov_note:            analysis.data_gov_note              || d.data_gov_label,
    overall_economic_verdict: analysis.overall_economic_verdict   || null,
    agent_notes:              analysis.agent_notes                || null
  }
}}];


// ── Output validation ──
const required_keys = Object.keys(analysis).filter(k => !k.startsWith('_') && !k.startsWith('raw'));
if (required_keys.length < 3 || analysis.parse_error) {
  analysis._validation_failed = true;
  analysis._validation_reason = analysis.parse_error ? 'JSON parse error' : 'Insufficient output fields (' + required_keys.length + ')';
}
analysis._validated_at = new Date().toISOString();
analysis._agent_version = 'v2';
